import{_ as t,o,c as a,a3 as i}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"Code Blocks","description":"Auto-detect languages, auto-format with Prettier, and edit code in a dedicated popup — all from inside Notely.","frontmatter":{"title":"Code Blocks","description":"Auto-detect languages, auto-format with Prettier, and edit code in a dedicated popup — all from inside Notely.","keywords":"code block, syntax highlighting, auto-format, prettier, code editor, language detection","category":"Editor"},"headers":[],"relativePath":"editor/code-blocks.md","filePath":"editor/code-blocks.md","lastUpdated":1784259316000}'),d={name:"editor/code-blocks.md"};function r(n,e,c,s,l,p){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="code-blocks" tabindex="-1">Code Blocks <a class="header-anchor" href="#code-blocks" aria-label="Permalink to &quot;Code Blocks&quot;">​</a></h1><p>Notely provides a rich experience for working with code inside Markdown notes: automatic language detection, one-click formatting with Prettier, and a dedicated full-screen code editor.</p><h2 id="insert-a-code-block" tabindex="-1">Insert a Code Block <a class="header-anchor" href="#insert-a-code-block" aria-label="Permalink to &quot;Insert a Code Block&quot;">​</a></h2><p>In Edit mode, use the toolbar <strong>Code</strong> button or type three backticks followed by a language name:</p><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">```python</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">def hello(name):</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    return f&quot;Hello, {name}!&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">```</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Notely renders the block with syntax highlighting in Preview and Split modes.</p><h2 id="auto-detect-language" tabindex="-1">Auto-Detect Language <a class="header-anchor" href="#auto-detect-language" aria-label="Permalink to &quot;Auto-Detect Language&quot;">​</a></h2><p>If you paste a code snippet without a language tag, Notely attempts to detect the language automatically:</p><ol><li>Paste code into an empty fenced block (<code>```</code> without a language).</li><li>Notely inspects the content and adds the correct language tag.</li><li>The block re-renders with appropriate highlighting.</li></ol><p>Supported auto-detected languages include JavaScript, TypeScript, Python, HTML, CSS, JSON, YAML, Bash, SQL, Go, Rust, and more.</p><h2 id="auto-format-with-prettier" tabindex="-1">Auto-Format with Prettier <a class="header-anchor" href="#auto-format-with-prettier" aria-label="Permalink to &quot;Auto-Format with Prettier&quot;">​</a></h2><p>In <strong>Preview</strong> mode, a toolbar appears on hover above each code block. Click the <strong>🪄 Format</strong> button to auto-format the code using Prettier:</p><ul><li>Applies consistent indentation</li><li>Normalizes quotes and semicolons</li><li>Respects the language-appropriate style</li></ul><p>The formatting is written back to the Markdown source automatically.</p><p>You can also trigger formatting from inside the dedicated code editor.</p><h2 id="dedicated-code-editor" tabindex="-1">Dedicated Code Editor <a class="header-anchor" href="#dedicated-code-editor" aria-label="Permalink to &quot;Dedicated Code Editor&quot;">​</a></h2><p>For a distraction-free editing experience:</p><ol><li>Switch to <strong>Preview</strong> mode.</li><li>Hover over any code block — a toolbar appears.</li><li>Click the <strong>✎ Edit</strong> button.</li></ol><p>The dedicated code editor opens with:</p><ul><li><strong>Syntax highlighting</strong> for the block&#39;s language</li><li><strong>Find and Replace</strong> (<code>Ctrl + F</code>)</li><li><strong>Language selector</strong> — switch the code language</li><li><strong>Line numbers</strong></li><li><strong>Format button</strong> — run Prettier from within the editor</li></ul><p>Click <strong>Save</strong> to write changes back to the note, or <strong>Cancel</strong> to discard.</p><h2 id="code-execution" tabindex="-1">Code Execution <a class="header-anchor" href="#code-execution" aria-label="Permalink to &quot;Code Execution&quot;">​</a></h2><p>You can run code snippets directly from your notes:</p><ol><li>Hover over a code block in <strong>Preview</strong> mode.</li><li>If the block is written in JavaScript (<code>js</code>, <code>javascript</code>) or Python (<code>py</code>, <code>python</code>), the <strong>▶ Run</strong> button in the hover toolbar will be active.</li><li>Click <strong>▶ Run</strong> to execute the script locally.</li><li>The output is displayed in a collapsible, high-contrast dark terminal output frame beneath the code block.</li></ol><p>You can also execute code from inside the <strong>Dedicated Code Editor</strong> modal using the <strong>Execute</strong> button in the top toolbar.</p><div class="warning custom-block"><p class="custom-block-title">Security Note</p><p>Running code execution spawns a local process on your machine using your local <code>node</code> or <code>python</code>/<code>python3</code> installation. Only run code from trusted workspaces and sources.</p></div><div class="info custom-block"><p class="custom-block-title">Execution Limits &amp; Loops</p><p>Code execution terminates automatically after 10 seconds. If your code hangs or enters an infinite loop, the runner will kill the subprocess safely and report a timeout error.</p></div><h2 id="supported-languages" tabindex="-1">Supported Languages <a class="header-anchor" href="#supported-languages" aria-label="Permalink to &quot;Supported Languages&quot;">​</a></h2><p>Notely supports highlighting for all <a href="https://highlightjs.org/" target="_blank" rel="noreferrer">highlight.js</a> languages, including:</p><table tabindex="0"><thead><tr><th>Category</th><th>Examples</th></tr></thead><tbody><tr><td>Web</td><td><code>html</code>, <code>css</code>, <code>javascript</code>, <code>typescript</code>, <code>jsx</code>, <code>tsx</code></td></tr><tr><td>Backend</td><td><code>python</code>, <code>go</code>, <code>rust</code>, <code>java</code>, <code>csharp</code>, <code>php</code>, <code>ruby</code></td></tr><tr><td>Data</td><td><code>json</code>, <code>yaml</code>, <code>toml</code>, <code>xml</code>, <code>sql</code></td></tr><tr><td>Shell</td><td><code>bash</code>, <code>powershell</code>, <code>cmd</code></td></tr><tr><td>Markup</td><td><code>markdown</code>, <code>latex</code></td></tr><tr><td>Config</td><td><code>nginx</code>, <code>dockerfile</code>, <code>makefile</code></td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Copy Button</p><p>Every code block in Preview mode has a <strong>Copy</strong> button in the top-right corner. Click it to copy the code contents without the backtick fences.</p></div><div class="tip custom-block"><p class="custom-block-title">Language Tags are Important</p><p>Always specify a language tag for better highlighting and to ensure the auto-formatter chooses the right rules. Example: <code>```typescript</code> instead of <code>```</code>.</p></div>',33)])])}const g=t(d,[["render",r]]);export{u as __pageData,g as default};
